/**
 * Admin Translation Management
 * Author: generated by Amazon Q
 * Created: 2024-01-15
 */

'use client';

import { useState, useEffect } from 'react';

interface Translation {
  id: string;
  key: string;
  language: string;
  value: string;
  namespace?: string;
}

export default function AdminTranslations() {
  const [translations, setTranslations] = useState<Record<string, Translation[]>>({});
  const [activeLanguage, setActiveLanguage] = useState<'en' | 'ar'>('en');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedNamespace, setSelectedNamespace] = useState<string>('all');
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [editingKey, setEditingKey] = useState<string | null>(null);

  useEffect(() => {
    fetchTranslations();
  }, []);

  const fetchTranslations = async () => {
    try {
      const token = localStorage.getItem('adminToken');
      if (!token) return;

      const response = await fetch('/api/admin/translations', {
        headers: { 'Authorization': `Bearer ${token}` },
      });

      if (response.ok) {
        const data = await response.json();
        
        // Convert flat translations to structured format
        const structured: Record<string, Translation[]> = {};
        
        for (const [lang, langTranslations] of Object.entries(data.translations)) {
          structured[lang] = Object.entries(langTranslations as Record<string, string>).map(([key, value]) => ({
            id: `${lang}-${key}`,
            key,
            language: lang,
            value: value as string,
            namespace: key.split('.')[0],
          }));
        }
        
        setTranslations(structured);
      }
    } catch (error) {
      console.error('Failed to fetch translations:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSave = async (key: string, newValue: string) => {
    setIsSaving(true);
    try {
      const token = localStorage.getItem('adminToken');
      if (!token) return;

      const translationToUpdate = {
        key,
        language: activeLanguage,
        value: newValue,
        namespace: key.split('.')[0],
      };

      const response = await fetch('/api/admin/translations', {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({
          translations: [translationToUpdate],
        }),
      });

      if (response.ok) {
        // Update local state
        setTranslations(prev => ({
          ...prev,
          [activeLanguage]: prev[activeLanguage].map(t =>
            t.key === key ? { ...t, value: newValue } : t
          ),
        }));
        setEditingKey(null);
      } else {
        alert('Failed to save translation');
      }
    } catch (error) {
      console.error('Save error:', error);
      alert('Failed to save translation');
    } finally {
      setIsSaving(false);
    }
  };

  const syncTranslations = async (direction: 'import' | 'export') => {
    try {
      const token = localStorage.getItem('adminToken');
      if (!token) return;

      const response = await fetch('/api/admin/translations/sync', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({ direction }),
      });

      if (response.ok) {
        const data = await response.json();
        alert(data.message);
        if (direction === 'import') {
          fetchTranslations(); // Refresh data after import
        }
      } else {
        alert('Sync failed');
      }
    } catch (error) {
      console.error('Sync error:', error);
      alert('Sync failed');
    }
  };

  const currentTranslations = translations[activeLanguage] || [];
  const namespaces = Array.from(new Set(currentTranslations.map(t => t.namespace).filter(Boolean))) as string[];
  
  const filteredTranslations = currentTranslations.filter(t => {
    const matchesSearch = t.key.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         t.value.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesNamespace = selectedNamespace === 'all' || t.namespace === selectedNamespace;
    return matchesSearch && matchesNamespace;
  });

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p className="text-gray-600 dark:text-gray-400">Loading translations...</p>
        </div>
      </div>
    );
  }

  return (
    <div>
      <div className="flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white">
            Translation Management
          </h1>
          <p className="mt-2 text-gray-600 dark:text-gray-400">
            Manage multilingual content for your website
          </p>
        </div>
        
        <div className="flex space-x-3">
          <button
            onClick={() => syncTranslations('import')}
            className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg font-medium transition-colors"
          >
            Import from Files
          </button>
          <button
            onClick={() => syncTranslations('export')}
            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-medium transition-colors"
          >
            Export to Files
          </button>
        </div>
      </div>

      {/* Language Tabs */}
      <div className="mb-6">
        <div className="flex space-x-1 bg-gray-100 dark:bg-gray-800 rounded-lg p-1">
          {['en', 'ar'].map((lang) => (
            <button
              key={lang}
              onClick={() => setActiveLanguage(lang as 'en' | 'ar')}
              className={`px-4 py-2 rounded-md font-medium transition-colors ${
                activeLanguage === lang
                  ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow'
                  : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white'
              }`}
            >
              {lang === 'en' ? '🇺🇸 English' : '🇸🇦 العربية'}
            </button>
          ))}
        </div>
      </div>

      {/* Filters */}
      <div className="mb-6 flex flex-col sm:flex-row gap-4">
        <div className="flex-1">
          <input
            type="text"
            placeholder="Search translations..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-800 text-gray-900 dark:text-white"
          />
        </div>
        
        <select
          value={selectedNamespace}
          onChange={(e) => setSelectedNamespace(e.target.value)}
          className="px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-800 text-gray-900 dark:text-white"
        >
          <option value="all">All Namespaces</option>
          {namespaces.map(ns => (
            <option key={ns} value={ns}>{ns}</option>
          ))}
        </select>
      </div>

      {/* Translations Table */}
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow overflow-hidden">
        <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
          <thead className="bg-gray-50 dark:bg-gray-700">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                Key
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                Value
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                Namespace
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                Actions
              </th>
            </tr>
          </thead>
          <tbody className="bg-white dark:bg-gray-800 divide-y divide-gray-200 dark:divide-gray-700">
            {filteredTranslations.map((translation) => (
              <tr key={translation.id} className="hover:bg-gray-50 dark:hover:bg-gray-700">
                <td className="px-6 py-4 whitespace-nowrap">
                  <div className="text-sm font-mono text-gray-900 dark:text-white">
                    {translation.key}
                  </div>
                </td>
                <td className="px-6 py-4">
                  {editingKey === translation.key ? (
                    <textarea
                      defaultValue={translation.value}
                      className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                      rows={2}
                      onBlur={(e) => handleSave(translation.key, e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter' && e.ctrlKey) {
                          handleSave(translation.key, e.currentTarget.value);
                        }
                        if (e.key === 'Escape') {
                          setEditingKey(null);
                        }
                      }}
                      autoFocus
                    />
                  ) : (
                    <div
                      className="text-sm text-gray-900 dark:text-white cursor-pointer hover:bg-gray-100 dark:hover:bg-gray-600 p-2 rounded"
                      onClick={() => setEditingKey(translation.key)}
                      dir={activeLanguage === 'ar' ? 'rtl' : 'ltr'}
                    >
                      {translation.value}
                    </div>
                  )}
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <span className="px-2 py-1 text-xs font-medium rounded-full bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-300">
                    {translation.namespace}
                  </span>
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                  <button
                    onClick={() => setEditingKey(translation.key)}
                    disabled={isSaving}
                    className="text-blue-600 hover:text-blue-900 dark:text-blue-400 dark:hover:text-blue-300 disabled:opacity-50"
                  >
                    {isSaving && editingKey === translation.key ? 'Saving...' : 'Edit'}
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {filteredTranslations.length === 0 && (
        <div className="text-center py-12">
          <div className="text-6xl mb-4">🔍</div>
          <h3 className="text-lg font-medium text-gray-900 dark:text-white mb-2">
            No translations found
          </h3>
          <p className="text-gray-600 dark:text-gray-400">
            Try adjusting your search or filter criteria
          </p>
        </div>
      )}
    </div>
  );
}